% -------------------------------------------------------------------------
% B03_Kinematics_3D_And_Cycles_R1_MLaxis.m
%
% Generated by: Seyed Mohammadali Rahmati
% Affiliation : Comparative Neuromechanics Lab,
%               School of Biological Sciences,
%               Georgia Institute of Technology, Atlanta, GA, USA
% Email       : smarahmati@gmail.com
%
% Description:
%   Computes rat hindlimb 3D kinematics after B01 registration.
%   This script builds pelvis, femur, tibia, and foot coordinate systems,
%   calculates hip/knee/ankle joint angles, normalizes gait cycles, and
%   stores the results in tables under Data.(TrialName).
%
% Required before running:
%   Run B01_Registration_WithoutFlow_3DScale_WithMWF.m first.
%   B03 uses transformed marker/STL variables created by B01.
%
% Notes:
%   alpha = flexion/extension angle
%   betha = abduction/adduction angle
%   gamma = internal/external rotation angle
%
%   Local anatomical axes used for each segment:
%     X axis = local i-axis = longitudinal / proximal-distal segment axis
%     Y axis = local j-axis = cross-product axis, perpendicular to X and Z
%     Z axis = local k-axis = medio-lateral axis from paired landmarks
%
%   EulerSeq explains the rotation order used by MATLAB rotm2eul():
%     'ZYX' means rotations are extracted about Z, then Y, then X.
%           In this script: alpha uses Z, betha uses Y, gamma uses X.
%           This is the default used here.
%     'XYZ' means rotations are extracted about X, then Y, then Z.
%           In this script: gamma uses X, betha uses Y, alpha uses Z.
%
%   Sign conventions are applied below separately for each side and joint,
%   so the y-axis labels define which direction is positive.
%
%   The variable name "betha" is kept for compatibility with older scripts
%   and saved result structures.
% -------------------------------------------------------------------------

%% -------------------------- User parameters -----------------------------
% Do not clear the workspace here. This script uses variables produced by B01.

EulerSeq = 'ZYX';                       % Euler sequence used by rotm2eul: 'ZYX' or 'XYZ'
Time_Nor = linspace(0, 100, 101);       % Normalized gait cycle vector, 0 to 100 percent

% Plotting switch.
%   true  = create diagnostic figures 100-107.
%   false = skip figures; useful during optimization for speed.
if ~exist('plotB03Figures', 'var') || isempty(plotB03Figures)
    plotB03Figures = true;
end

% Consistent colors for all figures.
% Right side is black. Left side is a soft blue that is easier to see than cyan.
rightPlotColor = [0.00, 0.00, 0.00];    % Right side curves and transition lines
leftPlotColor  = [0.20, 0.45, 0.95];    % Left side curves and transition lines

% Lighter versions are used only when many individual cycles are overlaid.
rightLightColor = [0.65, 0.65, 0.65];
leftLightColor  = [0.62, 0.75, 1.00];

% Plot labels are controlled by getAngleLabels() at the end of this file.
% Main local function in this script: computeJointAnglesFromAxes().

%% Initialize cycle variables
Time_CycR = [];
Trtime_CycR = [];
Duty_CycR = [];
CycR_Tr_Step = [];


Time_CycL = [];
Trtime_CycL = [];
Duty_CycL = [];
CycL_Tr_Step = [];

%% Compute segment coordinate systems

% PS: Pubic Symphysis
% FRH: Femur Right Head
% FRT: Femur Right Trochanter
% FRC: Femur Right Condyle
% TRP: Tibia Right Proximal Condyle
% TRH: Tibia Right Harp (distal fusion of the tibia and fibula)
% TRD: Tibia Right Distal Condyle (lateral malleolus of the tibia)
% CR: Calcaneus Right
% MR: Metatarsal Right
% FDPR: First Distal Phalange Right

% PelvisSTLpoints =  [RPHip; LPHip; PS]; 
% Pelvis_registered_STLpoints{}
% RPHip_transformed()
% LPHip_transformed()
% PS_transformed()

% RFemurSTLpoints =  [RFH; RFT; RFE];
% RFemur_registered_STLpoints{}
% RFH_transformed()
% RFT_transformed()
% RFE_transformed()
% RFKne_transformed() 
% RFEL_transformed() 
% RFEM_transformed() 

% LFemurSTLpoints =  [LFH; LFT; LFE];
% LFemur_registered_STLpoints{}
% LFH_transformed()
% LFT_transformed()
% LFE_transformed()
% LFKne_transformed() 
% LFEL_transformed() 
% LFEM_transformed() 

% RTibiaSTL5points =  [RTP; RTH; RTAnk; RTPAL; RTPAM]; 
% RTibia_registered_STLpoints{}
% RTP_transformed()
% RTH_transformed()
% RTKne_transformed() 
% RTAnk_transformed() 
% RTPAL_transformed() 
% RTPAM_transformed() 
% RTMAM_T_transformed() 
% RTMAL_T_transformed()

% LTibiaSTL5points =  [LTP; LTH; LTAnk; LTPAL; LTPAM]; 
% LTibia_registered_STLpoints{}
% LTP_transformed()
% LTH_transformed()
% LTKne_transformed() 
% LTAnk_transformed() 
% LTPAL_transformed() 
% LTPAM_transformed() 
% LTMAM_T_transformed() 
% LTMAL_T_transformed()

% RFootSTLpoints =  [RTMAM; RTMAL; RMet; RCal]; 
% RFoot_registered_STLpoints{}
% RTMAM_F_transformed()
% RTMAL_F_transformed()
% RMet_transformed()
% RCal_transformed()
% RFAnk_transformed()

% LFootSTLpoints =  [LTMAM; LTMAL; LMet; LCal]; 
% LFoot_registered_STLpoints{}
% LTMAM_F_transformed()
% LTMAL_F_transformed()
% LMet_transformed()
% LCal_transformed()
% LFAnk_transformed()


%------------------------Pelvis----------------------------------------
MASI_transformed = (RASI_transformed + LASI_transformed)/2;
Vj_p = cross((LPHip_transformed-MASI_transformed),(RPHip_transformed-MASI_transformed),2);
Vk_p = -(LPHip_transformed-RPHip_transformed);
j_pelvis = Vj_p./sqrt(diag(Vj_p*Vj_p'));
k_pelvis = Vk_p./sqrt(diag(Vk_p*Vk_p'));
i_pelvis = cross(j_pelvis, k_pelvis,2);
i_pelvis = i_pelvis./sqrt(diag(i_pelvis*i_pelvis'));


%------------- Method two (based on segment land markers) - better -------------
%------------Right Femur-----------
Vi_Rfemur = RFH_transformed-RFKne_transformed;
i_Rfemur = Vi_Rfemur./sqrt(diag(Vi_Rfemur*Vi_Rfemur'));
k_Rfemur =  RFEL_transformed-RFEM_transformed;
k_Rfemur = k_Rfemur./sqrt(diag(k_Rfemur*k_Rfemur'));

j_Rfemur = cross(k_Rfemur,i_Rfemur,2);
j_Rfemur = j_Rfemur./sqrt(diag(j_Rfemur*j_Rfemur'));
% i_Rfemur = cross(j_Rfemur,k_Rfemur,2);
% i_Rfemur = i_Rfemur./sqrt(diag(i_Rfemur*i_Rfemur'));
k_Rfemur = cross(i_Rfemur,j_Rfemur,2);
k_Rfemur = k_Rfemur./sqrt(diag(k_Rfemur*k_Rfemur'));


%------------Right Femur (second defination)-----------
% j_Rfemur = -cross((RFH_transformed-RFT_transformed), (RFH_transformed-RFE_transformed));
% j_Rfemur = j_Rfemur./sqrt(diag(j_Rfemur*j_Rfemur'));
% k_Rfemur = cross(i_Rfemur,j_Rfemur,2);
% k_Rfemur = k_Rfemur./sqrt(diag(k_Rfemur*k_Rfemur'));
% j_Rfemur = cross(k_Rfemur,i_Rfemur,2);
% j_Rfemur = j_Rfemur./sqrt(diag(j_Rfemur*j_Rfemur'));



%------------Right Leg------------
Vi_Rleg = RTKne_transformed-RTAnk_transformed;
i_Rleg = Vi_Rleg./sqrt(diag(Vi_Rleg*Vi_Rleg'));
k_Rleg = RTPAL_transformed-RTPAM_transformed;
k_Rleg = k_Rleg./sqrt(diag(k_Rleg*k_Rleg'));
j_Rleg = cross(k_Rleg,i_Rleg,2);
j_Rleg = j_Rleg./sqrt(diag(j_Rleg*j_Rleg'));
% i_Rleg = cross(j_Rleg,k_Rleg,2);
% i_Rleg = i_Rleg./sqrt(diag(i_Rleg*i_Rleg'));
k_Rleg = cross(i_Rleg,j_Rleg,2);
k_Rleg = k_Rleg./sqrt(diag(k_Rleg*k_Rleg'));



%------------Right Foot-----------
Vi_Rfoot = RCal_transformed-RMet_transformed;
i_Rfoot = Vi_Rfoot./sqrt(diag(Vi_Rfoot*Vi_Rfoot'));
k_Rfoot = RTMAL_F_transformed-RTMAM_F_transformed;
k_Rfoot = k_Rfoot./sqrt(diag(k_Rfoot*k_Rfoot'));
j_Rfoot = cross(k_Rfoot,i_Rfoot,2);
j_Rfoot = j_Rfoot./sqrt(diag(j_Rfoot*j_Rfoot'));
% i_Rfoot = cross(j_Rfoot,k_Rfoot,2);
% i_Rfoot = i_Rfoot./sqrt(diag(i_Rfoot*i_Rfoot'));
k_Rfoot = cross(i_Rfoot,j_Rfoot,2);
k_Rfoot = k_Rfoot./sqrt(diag(k_Rfoot*k_Rfoot'));


%------------Left Femur-----------
Vi_Lfemur = LFH_transformed-LFKne_transformed;
i_Lfemur = Vi_Lfemur./sqrt(diag(Vi_Lfemur*Vi_Lfemur'));
k_Lfemur =  -(LFEL_transformed-LFEM_transformed);
k_Lfemur = k_Lfemur./sqrt(diag(k_Lfemur*k_Lfemur'));
j_Lfemur = cross(k_Lfemur,i_Lfemur,2);
j_Lfemur = j_Lfemur./sqrt(diag(j_Lfemur*j_Lfemur'));
% i_Lfemur = cross(j_Lfemur,k_Lfemur,2);
% i_Lfemur = i_Lfemur./sqrt(diag(i_Lfemur*i_Lfemur'));
k_Lfemur = cross(i_Lfemur,j_Lfemur,2);
k_Lfemur = k_Lfemur./sqrt(diag(k_Lfemur*k_Lfemur'));


%------------Left Femur (second defination)-----------
% j_Lfemur = cross((LFH_transformed-LFT_transformed), (LFH_transformed-LFE_transformed));
% j_Lfemur = j_Lfemur./sqrt(diag(j_Lfemur*j_Lfemur'));
% k_Lfemur = cross(i_Lfemur,j_Lfemur,2);
% k_Lfemur = k_Lfemur./sqrt(diag(k_Lfemur*k_Lfemur'));
% j_Lfemur = cross(k_Lfemur,i_Lfemur,2);
% j_Lfemur = j_Lfemur./sqrt(diag(j_Lfemur*j_Lfemur'));



%------------Left Leg------------
Vi_Lleg = LTKne_transformed-LTAnk_transformed;
i_Lleg = Vi_Lleg./sqrt(diag(Vi_Lleg*Vi_Lleg'));
k_Lleg = -(LTPAL_transformed-LTPAM_transformed);
k_Lleg = k_Lleg./sqrt(diag(k_Lleg*k_Lleg'));
j_Lleg = cross(k_Lleg,i_Lleg,2);
j_Lleg = j_Lleg./sqrt(diag(j_Lleg*j_Lleg'));
% i_Lleg = cross(j_Lleg,k_Lleg,2);
% i_Lleg = i_Lleg./sqrt(diag(i_Lleg*i_Lleg'));
k_Lleg = cross(i_Lleg,j_Lleg,2);
k_Lleg = k_Lleg./sqrt(diag(k_Lleg*k_Lleg'));


%------------Left Foot-----------
Vi_Lfoot = LCal_transformed-LMet_transformed;
i_Lfoot = Vi_Lfoot./sqrt(diag(Vi_Lfoot*Vi_Lfoot'));
k_Lfoot = -(LTMAL_F_transformed-LTMAM_F_transformed);
k_Lfoot = k_Lfoot./sqrt(diag(k_Lfoot*k_Lfoot'));
j_Lfoot = cross(k_Lfoot,i_Lfoot,2);
j_Lfoot = j_Lfoot./sqrt(diag(j_Lfoot*j_Lfoot'));
% i_Lfoot = cross(j_Lfoot,k_Lfoot,2);
% i_Lfoot = i_Lfoot./sqrt(diag(i_Lfoot*i_Lfoot'));
k_Lfoot = cross(i_Lfoot,j_Lfoot,2);
k_Lfoot = k_Lfoot./sqrt(diag(k_Lfoot*k_Lfoot'));


%% Calculate joint angles
% Relative rotations are computed between adjacent segment frames:
%   Hip   : femur frame -> pelvis frame
%   Knee  : tibia frame -> femur frame
%   Ankle : foot frame  -> tibia frame
%
% The detailed loop is kept in one local function at the end of the file so
% the main script stays short and readable.

n = size(time, 1);

[R_Rhip, R_Rknee, R_Rankle, ...
 R_Lhip, R_Lknee, R_Lankle, ...
 Joint_Angles_Rhip, Joint_Angles_Rknee, Joint_Angles_Rankle, ...
 Joint_Angles_Lhip, Joint_Angles_Lknee, Joint_Angles_Lankle] = ...
    computeJointAnglesFromAxes( ...
        i_pelvis, j_pelvis, k_pelvis, ...
        i_Rfemur, j_Rfemur, k_Rfemur, ...
        i_Rleg,   j_Rleg,   k_Rleg, ...
        i_Rfoot,  j_Rfoot,  k_Rfoot, ...
        i_Lfemur, j_Lfemur, k_Lfemur, ...
        i_Lleg,   j_Lleg,   k_Lleg, ...
        i_Lfoot,  j_Lfoot,  k_Lfoot, ...
        EulerSeq);


%% Convert Euler angles to anatomical angles
% alpha = flexion/extension angle
% beta = Adduction/Abduction angle
% gamma = internal/external rotation angle

r2d = 180/pi;

if strcmp(EulerSeq, 'XYZ')==1

%--------------------Right--------------------------------
alpha_Rhip = Joint_Angles_Rhip(:,3)*r2d;
betha_Rhip = -Joint_Angles_Rhip(:,2)*r2d;  
gamma_Rhip = Joint_Angles_Rhip(:,1)*r2d; 

alpha_Rknee = Joint_Angles_Rknee(:,3)*r2d;
betha_Rknee = -Joint_Angles_Rknee(:,2)*r2d;  
gamma_Rknee = -Joint_Angles_Rknee(:,1)*r2d; 

alpha_Rankle = Joint_Angles_Rankle(:,3)*r2d;
betha_Rankle = -Joint_Angles_Rankle(:,2)*r2d;  
gamma_Rankle = Joint_Angles_Rankle(:,1)*r2d; 

%--------------------Left--------------------------------
alpha_Lhip =  Joint_Angles_Lhip(:,3)*r2d;
betha_Lhip =  Joint_Angles_Lhip(:,2)*r2d;  % see joint axes for hip
gamma_Lhip =  -Joint_Angles_Lhip(:,1)*r2d;  % see joint axes for hip

alpha_Lknee = Joint_Angles_Lknee(:,3)*r2d;
betha_Lknee = Joint_Angles_Lknee(:,2)*r2d;  
gamma_Lknee = Joint_Angles_Lknee(:,1)*r2d; 

alpha_Lankle = Joint_Angles_Lankle(:,3)*r2d;
betha_Lankle = Joint_Angles_Lankle(:,2)*r2d;  
gamma_Lankle = -Joint_Angles_Lankle(:,1)*r2d; 


alpha_Rhip = 90-(180+alpha_Rhip);
alpha_Lhip = 90-(180+alpha_Lhip);

alpha_Rknee = alpha_Rknee;
alpha_Lknee = alpha_Lknee;

alpha_Rankle = 90-(180+alpha_Rankle);
alpha_Lankle = 90-(180+alpha_Lankle);


elseif strcmp(EulerSeq, 'ZYX')==1


%--------------------Right--------------------------------
alpha_Rhip = Joint_Angles_Rhip(:,1)*r2d;
betha_Rhip = -Joint_Angles_Rhip(:,2)*r2d;  
gamma_Rhip = Joint_Angles_Rhip(:,3)*r2d; 

alpha_Rknee = Joint_Angles_Rknee(:,1)*r2d;
betha_Rknee = -Joint_Angles_Rknee(:,2)*r2d;  
gamma_Rknee = Joint_Angles_Rknee(:,3)*r2d; 

alpha_Rankle = Joint_Angles_Rankle(:,1)*r2d;
betha_Rankle = Joint_Angles_Rankle(:,2)*r2d;  
gamma_Rankle = Joint_Angles_Rankle(:,3)*r2d; 

%--------------------Left--------------------------------
alpha_Lhip =  Joint_Angles_Lhip(:,1)*r2d;
betha_Lhip =  Joint_Angles_Lhip(:,2)*r2d;  % see joint axes for hip
gamma_Lhip =  -Joint_Angles_Lhip(:,3)*r2d;  % see joint axes for hip

alpha_Lknee = Joint_Angles_Lknee(:,1)*r2d;
betha_Lknee = Joint_Angles_Lknee(:,2)*r2d;  
gamma_Lknee = -Joint_Angles_Lknee(:,3)*r2d; 

alpha_Lankle = Joint_Angles_Lankle(:,1)*r2d;
betha_Lankle = -Joint_Angles_Lankle(:,2)*r2d;  
gamma_Lankle = -Joint_Angles_Lankle(:,3)*r2d; 


alpha_Rhip = 90-(180+alpha_Rhip);
alpha_Lhip = 90-(180+alpha_Lhip);

alpha_Rknee = alpha_Rknee;
alpha_Lknee = alpha_Lknee;

alpha_Rankle = 90-(180+alpha_Rankle);
alpha_Lankle = 90-(180+alpha_Lankle);


end


 

%% Pelvis height & orientation

Z_ground = mean([min(RMet_transformed(:,3)), min(LMet_transformed(:,3))]);

pelvis_height = PS_transformed(:,3)-Z_ground;


% i_pelvis, k_pelvis, j_pelvis are each n-by-3
%  i_pelvis(t,:) = local forward axis at time t
%  k_pelvis(t,:) = local lateral axis (left->right)
%  j_pelvis(t,:) = local upward axis

% -- 1) Yaw: angle in horizontal plane between i_pelvis & global forward
i_xy    = i_pelvis(:,1:2);                     % [ix, iy]
yaw_rad = atan2( i_xy(:,2), i_xy(:,1) );
pelvis_rotation_angle = rad2deg( yaw_rad );

% -- 2) Pitch: angle of i_pelvis vs. horizontal
ix = i_pelvis(:,1);
iy = i_pelvis(:,2);
iz = i_pelvis(:,3);

pitch_rad = atan2( iz, sqrt(ix.^2 + iy.^2) );
pelvis_tilt_angle = rad2deg(pitch_rad);

% -- 3) Roll: angle of k_pelvis vs. horizontal
kx = k_pelvis(:,1);
ky = k_pelvis(:,2);
kz = k_pelvis(:,3);

roll_rad = atan2( kz, sqrt(kx.^2 + ky.^2) );
pelvis_list_angle = rad2deg(roll_rad);

% Now yaw_deg(t), pitch_deg(t), roll_deg(t) contain angles in degrees 
%  for each time step t. 


% i_pelvis, j_pelvis, k_pelvis are n-by-3, 
% each row is [x y z] for that vector at time t.

for t = 1:size(i_pelvis,1)

    % Build the 3x3 matrix by columns:
    %   First column = X = i_pelvis(t,:)
    %   Second column= Y = j_pelvis(t,:)
    %   Third column = Z = k_pelvis(t,:)
    R = [i_pelvis(t,:)' , ... % roll
         j_pelvis(t,:)' , ... % yaw
         k_pelvis(t,:)' ];    % pitch

    % Extract angles using the 'XYZ' intrinsic Tait-Bryan sequence.
    % This yields [angleX, angleY, angleZ] = [pelvis_list, pelvis_rotation, pelvis_tilt]
    eul = rotm2eul(R, 'XYZ'); % YZX, XYZ, 
    
    pelvis_list_roll(t,1)      = -rad2deg(eul(1))+90;  % rotation about X
    pelvis_rotation_yaw(t,1)      = rad2deg(eul(2));    % rotation about Y
    pelvis_tilt_pitch(t,1)  = rad2deg(eul(3));   % rotation about Z

end


%% Total segment length

Femur_Len = mean(sqrt(sum((RFH_transformed - RFKne_transformed).^2, 2)));

Tibia_Len = mean(sqrt(sum((RTKne_transformed - RTAnk_transformed).^2, 2)));

Foot_Len = mean(sqrt(sum((RFAnk_transformed - RMet_transformed).^2, 2)));


Pelvis_ML_Len = mean(sqrt(sum((RPHip_transformed - LPHip_transformed).^2, 2)));

MidPHip_transformed = (RPHip_transformed+LPHip_transformed)/2;
MidASI_transformed = (RASI_transformed+LASI_transformed)/2;
Pelvis_AP_Len = mean(sqrt(sum((MidPHip_transformed - MidASI_transformed).^2, 2)));


%% Leg length and orientation

%--------------------------Right leg ------------------------------------------------------------------------
RLeg_Len = sqrt(sum((RFH_transformed - RMet_transformed).^2, 2)); 

Vec_Rleg = RFH_transformed - RMet_transformed;

VecN_Rleg = Vec_Rleg./RLeg_Len;

xaxis = [1, 0, 0];

% Calculate the dot product between each row of i_pelvis and zaxis
dot_product = VecN_Rleg * xaxis';

% Since i_pelvis rows are normalized, we can directly calculate the angles
angle_rad = acos(dot_product); % Angles in radians

% Convert the angles to degrees
RLeg_angle = 180-rad2deg(angle_rad);


%--------------------------left leg ------------------------------------------------------------------------
LLeg_Len = sqrt(sum((LFH_transformed - LMet_transformed).^2, 2)); 

Vec_Lleg = LFH_transformed - LMet_transformed;

VecN_Lleg = Vec_Lleg./LLeg_Len;

xaxis = [1, 0, 0];

% Calculate the dot product between each row of i_pelvis and zaxis
dot_product = VecN_Lleg * xaxis';

% Since i_pelvis rows are normalized, we can directly calculate the angles
angle_rad = acos(dot_product); % Angles in radians

% Convert the angles to degrees
LLeg_angle = 180-rad2deg(angle_rad);


%% Events

%---------Right cycles--------------------------------------------------------------------------------------
CycR_ISt_Step = TR_CycleEvents.R_ISt;   % Initial stance (Foot contact)
CycR_MSt_Step = TR_CycleEvents.R_MSt;   % Mid stance
CycR_TSt_Step = TR_CycleEvents.R_TSt;   % Terminal stance
CycR_MSw_Step = TR_CycleEvents.R_MSw;   % Mid swing
CycR_TSw_Step = TR_CycleEvents.R_TSw;   % Terminal swing

CycR_ISt_Time = (CycR_ISt_Step-1)*dt;
CycR_MSt_Time = (CycR_MSt_Step-1)*dt;
CycR_TSt_Time = (CycR_TSt_Step-1)*dt;
CycR_MSw_Time = (CycR_MSw_Step-1)*dt;
CycR_TSw_Time = (CycR_TSw_Step-1)*dt;

%---------Left cycles---------------------------------------------------------------------------------------
CycL_ISt_Step = TL_CycleEvents.L_ISt;   % Initial stance (Foot contact)
CycL_MSt_Step = TL_CycleEvents.L_MSt;   % Mid stance
CycL_TSt_Step = TL_CycleEvents.L_TSt;   % Terminal stance
CycL_MSw_Step = TL_CycleEvents.L_MSw;   % Mid swing
CycL_TSw_Step = TL_CycleEvents.L_TSw;   % Terminal swing

CycL_ISt_Time = (CycL_ISt_Step-1)*dt;
CycL_MSt_Time = (CycL_MSt_Step-1)*dt;
CycL_TSt_Time = (CycL_TSt_Step-1)*dt;
CycL_MSw_Time = (CycL_MSw_Step-1)*dt;
CycL_TSw_Time = (CycL_TSw_Step-1)*dt;


%---------Right cycles--------------------------------------------------------------------------------------
for i= 1:length(CycR_ISt_Step)
 Time_CycR{i,1} = time(CycR_ISt_Step(i):CycR_TSw_Step(i))-time(CycR_ISt_Step(i));  % set time zero at initial stance
 Trtime_CycR(i,1) = time(CycR_TSt_Step(i))-time(CycR_ISt_Step(i)); % with respect to initial stance
 Duty_CycR(i,1) = (time(CycR_TSt_Step(i))-time(CycR_ISt_Step(i)))/(time(CycR_TSw_Step(i))-time(CycR_ISt_Step(i))); % stance over cycle

 alpha_Rhip_Cyc{i,1} = alpha_Rhip(CycR_ISt_Step(i):CycR_TSw_Step(i));
 betha_Rhip_Cyc{i,1} = betha_Rhip(CycR_ISt_Step(i):CycR_TSw_Step(i));
 gamma_Rhip_Cyc{i,1} = gamma_Rhip(CycR_ISt_Step(i):CycR_TSw_Step(i));

 alpha_Rknee_Cyc{i,1} = alpha_Rknee(CycR_ISt_Step(i):CycR_TSw_Step(i));
 betha_Rknee_Cyc{i,1} = betha_Rknee(CycR_ISt_Step(i):CycR_TSw_Step(i));
 gamma_Rknee_Cyc{i,1} = gamma_Rknee(CycR_ISt_Step(i):CycR_TSw_Step(i));

 alpha_Rankle_Cyc{i,1} = alpha_Rankle(CycR_ISt_Step(i):CycR_TSw_Step(i));
 betha_Rankle_Cyc{i,1} = betha_Rankle(CycR_ISt_Step(i):CycR_TSw_Step(i));
 gamma_Rankle_Cyc{i,1} = gamma_Rankle(CycR_ISt_Step(i):CycR_TSw_Step(i));


RLeg_Len_Cyc{i,1} = RLeg_Len(CycR_ISt_Step(i):CycR_TSw_Step(i));
RLeg_angle_Cyc{i,1} = RLeg_angle(CycR_ISt_Step(i):CycR_TSw_Step(i));
end



%---------Left cycles--------------------------------------------------------------------------------------
for i= 1:length(CycL_ISt_Step)
 Time_CycL{i,1} = time(CycL_ISt_Step(i):CycL_TSw_Step(i))-time(CycL_ISt_Step(i));  % set time zero at initial stance
 Trtime_CycL(i,1) = time(CycL_TSt_Step(i))-time(CycL_ISt_Step(i)); % with respect to initial stance
 Duty_CycL(i,1) = (time(CycL_TSt_Step(i))-time(CycL_ISt_Step(i)))/(time(CycL_TSw_Step(i))-time(CycL_ISt_Step(i))); % stance over cycle

 alpha_Lhip_Cyc{i,1} = alpha_Lhip(CycL_ISt_Step(i):CycL_TSw_Step(i));
 betha_Lhip_Cyc{i,1} = betha_Lhip(CycL_ISt_Step(i):CycL_TSw_Step(i));
 gamma_Lhip_Cyc{i,1} = gamma_Lhip(CycL_ISt_Step(i):CycL_TSw_Step(i));

 alpha_Lknee_Cyc{i,1} = alpha_Lknee(CycL_ISt_Step(i):CycL_TSw_Step(i));
