pelvis_tilt_angle_Cyc{i,1} = pelvis_tilt_angle(CycL_ISt_Step(i):CycL_TSw_Step(i));
pelvis_rotation_angle_Cyc{i,1} = pelvis_rotation_angle(CycL_ISt_Step(i):CycL_TSw_Step(i));
pelvis_list_angle_Cyc{i,1} = pelvis_list_angle(CycL_ISt_Step(i):CycL_TSw_Step(i));
pelvis_tilt_pitch_Cyc{i,1} = pelvis_tilt_pitch(CycL_ISt_Step(i):CycL_TSw_Step(i));
pelvis_rotation_yaw_Cyc{i,1} = pelvis_rotation_yaw(CycL_ISt_Step(i):CycL_TSw_Step(i));
pelvis_list_roll_Cyc{i,1} = pelvis_list_roll(CycL_ISt_Step(i):CycL_TSw_Step(i));


