LLeg_angle_Cyc{i,1} = LLeg_angle(CycL_ISt_Step(i):CycL_TSw_Step(i));

end



%% Interpolation for normalizing cycles

% Time_Nor is defined in the user parameters section above.



for i = 1:length(CycR_ISt_Step)

% Normalize the time vector to range from 0 to 100
timeNormalized = 100 * Time_CycR{i,1} / max(Time_CycR{i,1});
timeNormalized(end)=100;

Trtime_CycR_Nor(i,1) = 100*Duty_CycR(i,1);

% Interpolate the force data
alpha_Rhip_Cyc_Nor{i,1} = interp1(timeNormalized, alpha_Rhip_Cyc{i,1}, Time_Nor)';
betha_Rhip_Cyc_Nor{i,1} = interp1(timeNormalized, betha_Rhip_Cyc{i,1}, Time_Nor)';
