%% Variables for a specific time


%% -------------------------------------------------------Hip stance phase -----------------------------------------------------------------
%-------------------------------------Sagittal plane-------------------------------------------
%-------------------Right-------------------------
%Initial stance
alpha_Rhip_ISt_Idx = CycR_ISt_Step;
alpha_Rhip_ISt = alpha_Rhip(CycR_ISt_Step);

%Terminal stance
alpha_Rhip_TSt_Idx = CycR_TSt_Step;
alpha_Rhip_TSt = alpha_Rhip(CycR_TSt_Step);

%Maximum extension
[alpha_Rhip_MaxExtSt, alpha_Rhip_MaxExtSt_Idx] = arrayfun(@(i, j) min_index(alpha_Rhip, i, j), CycR_ISt_Step, CycR_TSt_Step);

%Displacement
alpha_Rhip_Dis_ISt_MaxExtSt = alpha_Rhip_ISt - alpha_Rhip_MaxExtSt;

%-------------------Left-------------------------
%Initial stance
alpha_Lhip_ISt_Idx = CycL_ISt_Step;
alpha_Lhip_ISt = alpha_Lhip(CycL_ISt_Step);

%Terminal stance
alpha_Lhip_TSt_Idx = CycL_TSt_Step;
alpha_Lhip_TSt = alpha_Lhip(CycL_TSt_Step);

%Maximum extension
[alpha_Lhip_MaxExtSt, alpha_Lhip_MaxExtSt_Idx] = arrayfun(@(i, j) min_index(alpha_Lhip, i, j), CycL_ISt_Step, CycL_TSt_Step);

%Displacement
alpha_Lhip_Dis_ISt_MaxExtSt = alpha_Lhip_ISt - alpha_Lhip_MaxExtSt;


%-------------------------------------Frontal plane-------------------------------------------
%-------------------Right-------------------------
%Initial stance
betha_Rhip_ISt_Idx = CycR_ISt_Step;
betha_Rhip_ISt = betha_Rhip(CycR_ISt_Step);

%Terminal stance
betha_Rhip_TSt_Idx = CycR_TSt_Step;
betha_Rhip_TSt = betha_Rhip(CycR_TSt_Step);

%Maximum abduction
[betha_Rhip_MaxAddSt, betha_Rhip_MaxAddSt_Idx] = arrayfun(@(i, j) max_index(betha_Rhip, i, j), CycR_ISt_Step, CycR_TSt_Step);

%Displacement
betha_Rhip_Dis_ISt_MaxAddSt = -1*(betha_Rhip_ISt - betha_Rhip_MaxAddSt);


%-------------------Left-------------------------
%Initial stance
betha_Lhip_ISt_Idx = CycR_ISt_Step;
betha_Lhip_ISt = betha_Lhip(CycL_ISt_Step);

%Terminal stance
betha_Lhip_TSt_Idx = CycL_TSt_Step;
betha_Lhip_TSt = betha_Lhip(CycL_TSt_Step);

%Maximum abduction
[betha_Lhip_MaxAddSt, betha_Lhip_MaxAddSt_Idx] = arrayfun(@(i, j) max_index(betha_Lhip, i, j), CycL_ISt_Step, CycL_TSt_Step);

%Displacement
betha_Lhip_Dis_ISt_MaxAddSt = -1*(betha_Lhip_ISt - betha_Lhip_MaxAddSt);


%-------------------------------------Transverse plane-------------------------------------------
%-------------------Right-------------------------
%Initial stance
gamma_Rhip_ISt_Idx = CycR_ISt_Step;
gamma_Rhip_ISt = gamma_Rhip(CycR_ISt_Step);

%Terminal stance
gamma_Rhip_TSt_Idx = CycR_TSt_Step;
gamma_Rhip_TSt = gamma_Rhip(CycR_TSt_Step);

%Maximum internal rotation
[gamma_Rhip_MaxIntRSt, gamma_Rhip_MaxIntRSt_Idx] = arrayfun(@(i, j) max_index(gamma_Rhip, i, j), CycR_ISt_Step, CycR_TSt_Step);

%Maximum external rotation
[gamma_Rhip_MaxExtRSt, gamma_Rhip_MaxExtRSt_Idx] = arrayfun(@(i, j) min_index(gamma_Rhip, i, j), CycR_ISt_Step, CycR_TSt_Step);

%Displacement
gamma_Rhip_Dis_ISt_MaxIntRSt = -(gamma_Rhip_ISt - gamma_Rhip_MaxIntRSt);
gamma_Rhip_Dis_ISt_MaxExtRSt = (gamma_Rhip_ISt - gamma_Rhip_MaxExtRSt);
gamma_Rhip_Dis_MaxExtRSt_MaxIntRSt = -(gamma_Rhip_MaxExtRSt - gamma_Rhip_MaxIntRSt);


%-------------------Left-------------------------
%Initial stance
gamma_Lhip_ISt_Idx = CycL_ISt_Step;
gamma_Lhip_ISt = gamma_Lhip(CycL_ISt_Step);

%Terminal stance
gamma_Lhip_TSt_Idx = CycL_TSt_Step;
gamma_Lhip_TSt = gamma_Lhip(CycL_TSt_Step);

%Maximum internal rotation
[gamma_Lhip_MaxIntRSt, gamma_Lhip_MaxIntRSt_Idx] = arrayfun(@(i, j) max_index(gamma_Lhip, i, j), CycL_ISt_Step, CycL_TSt_Step);

%Maximum external rotation
[gamma_Lhip_MaxExtRSt, gamma_Lhip_MaxExtRSt_Idx] = arrayfun(@(i, j) min_index(gamma_Lhip, i, j), CycL_ISt_Step, CycL_TSt_Step);

%Displacement
gamma_Lhip_Dis_ISt_MaxIntRSt = -(gamma_Lhip_ISt - gamma_Lhip_MaxIntRSt);
gamma_Lhip_Dis_ISt_MaxExtRSt = (gamma_Lhip_ISt - gamma_Lhip_MaxExtRSt);
gamma_Lhip_Dis_MaxExtRSt_MaxIntRSt = -(gamma_Lhip_MaxExtRSt - gamma_Lhip_MaxIntRSt);



%% -------------------------------------------------------Hip swing phase -----------------------------------------------------------------
%-------------------------------------Sagittal plane-------------------------------------------
%-------------------Right-------------------------
%Terminal swing. Note: Initial swing is the same as terminal stance 
alpha_Rhip_TSw_Idx = CycR_TSw_Step;
alpha_Rhip_TSw = alpha_Rhip(CycR_TSw_Step);

%Maximum flexion
[alpha_Rhip_MaxFlxSw, alpha_Rhip_MaxFlxSw_Idx] = arrayfun(@(i, j) max_index(alpha_Rhip, i, j), CycR_TSt_Step, CycR_TSw_Step);


%-------------------Left-------------------------
%Terminal swing. Note: Initial swing is the same as terminal stance 
alpha_Lhip_TSw_Idx = CycL_TSw_Step;
alpha_Lhip_TSw = alpha_Lhip(CycL_TSw_Step);

%Maximum flexion
[alpha_Lhip_MaxFlxSw, alpha_Lhip_MaxFlxSw_Idx] = arrayfun(@(i, j) max_index(alpha_Lhip, i, j), CycL_TSt_Step, CycL_TSw_Step);


%-------------------------------------Frontal plane-------------------------------------------
%-------------------Right-------------------------
%Terminal swing. Note: Initial swing is the same as terminal stance 
betha_Rhip_TSw_Idx = CycR_TSw_Step;
betha_Rhip_TSw = betha_Rhip(CycR_TSw_Step);

%Maximum abduction
[betha_Rhip_MaxAbdSw, betha_Rhip_MaxAbdSw_Idx] = arrayfun(@(i, j) min_index(betha_Rhip, i, j), CycR_TSt_Step, CycR_TSw_Step);


%-------------------Left-------------------------
%Terminal swing. Note: Initial swing is the same as terminal stance 
betha_Lhip_TSw_Idx = CycL_TSw_Step;
betha_Lhip_TSw = betha_Lhip(CycL_TSw_Step);

%Maximum abduction
[betha_Lhip_MaxAbdSw, betha_Lhip_MaxAbdSw_Idx] = arrayfun(@(i, j) min_index(betha_Lhip, i, j), CycL_TSt_Step, CycL_TSw_Step);


%-------------------------------------Transverse plane-------------------------------------------
%-------------------Right-------------------------
%Terminal swing. Note: Initial swing is the same as terminal stance 
gamma_Rhip_TSw_Idx = CycR_TSw_Step;
gamma_Rhip_TSw = gamma_Rhip(CycR_TSw_Step);

%Maximum internal rotation
[gamma_Rhip_MaxIntRSw, gamma_Rhip_MaxIntRSw_Idx] = arrayfun(@(i, j) max_index(gamma_Rhip, i, j), CycR_TSt_Step, CycR_TSw_Step);


%-------------------Left-------------------------
%Terminal swing. Note: Initial swing is the same as terminal stance 
gamma_Lhip_TSw_Idx = CycL_TSw_Step;
gamma_Lhip_TSw = gamma_Lhip(CycL_TSw_Step);

%Maximum internal rotation
[gamma_Lhip_MaxIntRSw, gamma_Lhip_MaxIntRSw_Idx] = arrayfun(@(i, j) max_index(gamma_Lhip, i, j), CycL_TSt_Step, CycL_TSw_Step);


%% -------------------------------------------------------Hip total range of movement -----------------------------------------------------------------
%-------------------------------------Sagittal plane-------------------------------------------
%-------------------Right-------------------------
%Maximum flexion
[alpha_Rhip_MaxFlx, alpha_Rhip_MaxFlx_Idx] = arrayfun(@(i, j) max_index(alpha_Rhip, i, j), CycR_ISt_Step, CycR_TSw_Step);

%Maximum extension
[alpha_Rhip_MaxExt, alpha_Rhip_MaxExt_Idx] = arrayfun(@(i, j) min_index(alpha_Rhip, i, j), CycR_ISt_Step, CycR_TSw_Step);
alpha_Rhip_ROM = alpha_Rhip_MaxFlx - alpha_Rhip_MaxExt;

%-------------------Left-------------------------
%Maximum flexion
[alpha_Lhip_MaxFlx, alpha_Lhip_MaxFlx_Idx] = arrayfun(@(i, j) max_index(alpha_Lhip, i, j), CycL_ISt_Step, CycL_TSw_Step);

%Maximum extension
[alpha_Lhip_MaxExt, alpha_Lhip_MaxExt_Idx] = arrayfun(@(i, j) min_index(alpha_Lhip, i, j), CycL_ISt_Step, CycL_TSw_Step);
alpha_Lhip_ROM = alpha_Lhip_MaxFlx - alpha_Lhip_MaxExt;


%-------------------------------------Frontal plane-------------------------------------------
%-------------------Right-------------------------
%Maximum abduction
[betha_Rhip_MaxAbd, betha_Rhip_MaxAbd_Idx] = arrayfun(@(i, j) min_index(betha_Rhip, i, j), CycR_ISt_Step, CycR_TSw_Step);

%Maximum adduction
[betha_Rhip_MaxAdd, betha_Rhip_MaxAdd_Idx] = arrayfun(@(i, j) max_index(betha_Rhip, i, j), CycR_ISt_Step, CycR_TSw_Step);
betha_Rhip_ROM =  betha_Rhip_MaxAdd - betha_Rhip_MaxAbd;

%-------------------Left-------------------------
%Maximum abduction
[betha_Lhip_MaxAbd, betha_Lhip_MaxAbd_Idx] = arrayfun(@(i, j) min_index(betha_Lhip, i, j), CycL_ISt_Step, CycL_TSw_Step);

%Maximum adduction
[betha_Lhip_MaxAdd, betha_Lhip_MaxAdd_Idx] = arrayfun(@(i, j) max_index(betha_Lhip, i, j), CycL_ISt_Step, CycL_TSw_Step);
