alpha_Lankle_Dis_ISt_MaxDFlxSt = -1*(alpha_Lankle_ISt - alpha_Lankle_MaxDFlxSt);
alpha_Lankle_Dis_MaxDFlxSt_MaxPFlxSt = -1*(alpha_Lankle_MaxPFlxSt - alpha_Lankle_MaxDFlxSt);

%-------------------------------------Frontal plane-------------------------------------------
%-------------------Right-------------------------
%Initial stance
gamma_Rankle_ISt_Idx = CycR_ISt_Step;
gamma_Rankle_ISt = gamma_Rankle(CycR_ISt_Step);

%Terminal stance
gamma_Rankle_TSt_Idx = CycR_TSt_Step;
gamma_Rankle_TSt = gamma_Rankle(CycR_TSt_Step);

%Maximum external rotation (inversion)
[gamma_Rankle_MaxExtRSt, gamma_Rankle_MaxExtRSt_Idx] = arrayfun(@(i, j) min_index(gamma_Rankle, i, j), CycR_ISt_Step, CycR_TSt_Step);

%Maximum internal rotation (eversion)
[gamma_Rankle_MaxIntRSt, gamma_Rankle_MaxIntRSt_Idx] = arrayfun(@(i, j) max_index(gamma_Rankle, i, j), CycR_ISt_Step + floor(0.25*(CycR_TSt_Step-CycR_ISt_Step)), CycR_TSt_Step);

%Displacement
gamma_Rankle_Dis_ISt_MaxExtRSt = (gamma_Rankle_ISt - gamma_Rankle_MaxExtRSt);
gamma_Rankle_Dis_MaxExtRSt_MaxIntRSt = (gamma_Rankle_MaxIntRSt - gamma_Rankle_MaxExtRSt);


%-------------------Left-------------------------
%Initial stance
gamma_Lankle_ISt_Idx = CycR_ISt_Step;
gamma_Lankle_ISt = gamma_Lankle(CycL_ISt_Step);

%Terminal stance
gamma_Lankle_TSt_Idx = CycL_TSt_Step;
gamma_Lankle_TSt = gamma_Lankle(CycL_TSt_Step);

%Maximum external rotation (inversion)
[gamma_Lankle_MaxExtRSt, gamma_Lankle_MaxExtRSt_Idx] = arrayfun(@(i, j) min_index(gamma_Lankle, i, j), CycL_ISt_Step, CycL_TSt_Step);

%Maximum internal rotation (eversion)
[gamma_Lankle_MaxIntRSt, gamma_Lankle_MaxIntRSt_Idx] = arrayfun(@(i, j) max_index(gamma_Lankle, i, j), CycL_ISt_Step + floor(0.25*(CycL_TSt_Step-CycL_ISt_Step)), CycL_TSt_Step);


%Displacement
gamma_Lankle_Dis_ISt_MaxExtRSt = (gamma_Lankle_ISt - gamma_Lankle_MaxExtRSt);
gamma_Lankle_Dis_MaxExtRSt_MaxIntRSt = (gamma_Lankle_MaxIntRSt - gamma_Lankle_MaxExtRSt);



%-------------------------------------Transverse plane-------------------------------------------
%-------------------Right-------------------------
%Initial stance
betha_Rankle_ISt_Idx = CycR_ISt_Step;
betha_Rankle_ISt = betha_Rankle(CycR_ISt_Step);

%Terminal stance
betha_Rankle_TSt_Idx = CycR_TSt_Step;
betha_Rankle_TSt = betha_Rankle(CycR_TSt_Step);

%Maximum abduction
[betha_Rankle_MaxAbdSt, betha_Rankle_MaxAbdSt_Idx] = arrayfun(@(i, j) min_index(betha_Rankle, i, j), CycR_ISt_Step, CycR_TSt_Step);


%Displacement
betha_Rankle_Dis_ISt_MaxAbdSt = (betha_Rankle_ISt - betha_Rankle_MaxAbdSt);


%-------------------Left-------------------------
%Initial stance
betha_Lankle_ISt_Idx = CycL_ISt_Step;
betha_Lankle_ISt = betha_Lankle(CycL_ISt_Step);

%Terminal stance
betha_Lankle_TSt_Idx = CycL_TSt_Step;
betha_Lankle_TSt = betha_Lankle(CycL_TSt_Step);

%Maximum abduction
[betha_Lankle_MaxAbdSt, betha_Lankle_MaxAbdSt_Idx] = arrayfun(@(i, j) min_index(betha_Lankle, i, j), CycL_ISt_Step, CycL_TSt_Step);


%Displacement
betha_Lankle_Dis_ISt_MaxAbdSt = (betha_Lankle_ISt - betha_Lankle_MaxAbdSt);



%% -------------------------------------------------------Ankle swing phase -----------------------------------------------------------------
%-------------------------------------Sagittal plane-------------------------------------------
%-------------------Right-------------------------
%Terminal swing. Note: Initial swing is the same as terminal stance 
alpha_Rankle_TSw_Idx = CycR_TSw_Step;
alpha_Rankle_TSw = alpha_Rankle(CycR_TSw_Step);

%Maximum dorsi-flexion
[alpha_Rankle_MaxDFlxSw, alpha_Rankle_MaxDFlxSw_Idx] = arrayfun(@(i, j) max_index(alpha_Rankle, i, j), CycR_TSt_Step, CycR_TSw_Step);


%-------------------Left-------------------------
%Terminal swing. Note: Initial swing is the same as terminal stance 
alpha_Lankle_TSw_Idx = CycL_TSw_Step;
alpha_Lankle_TSw = alpha_Lankle(CycL_TSw_Step);

%Maximum flexion
[alpha_Lankle_MaxDFlxSw, alpha_Lankle_MaxDFlxSw_Idx] = arrayfun(@(i, j) max_index(alpha_Lankle, i, j), CycL_TSt_Step, CycL_TSw_Step);


%-------------------------------------Frontal plane-------------------------------------------
%-------------------Right-------------------------
%Terminal swing. Note: Initial swing is the same as terminal stance 
gamma_Rankle_TSw_Idx = CycR_TSw_Step;
gamma_Rankle_TSw = gamma_Rankle(CycR_TSw_Step);

%Maximum internal rotation (eversion)
[gamma_Rankle_MaxIntRSw, gamma_Rankle_MaxIntRSw_Idx] = arrayfun(@(i, j) max_index(gamma_Rankle, i, j), CycR_TSt_Step, CycR_TSw_Step - floor(0.25*(CycR_TSw_Step-CycR_TSt_Step)));


%-------------------Left-------------------------
%Terminal swing. Note: Initial swing is the same as terminal stance 
gamma_Lankle_TSw_Idx = CycL_TSw_Step;
gamma_Lankle_TSw = gamma_Lankle(CycL_TSw_Step);

%Maximum inrernal rotation (eversion)
[gamma_Lankle_MaxIntRSw, gamma_Lankle_MaxIntRSw_Idx] = arrayfun(@(i, j) max_index(gamma_Lankle, i, j), CycL_TSt_Step, CycL_TSw_Step - floor(0.25*(CycL_TSw_Step-CycL_TSt_Step)));


%-------------------------------------Transverse plane-------------------------------------------
%-------------------Right-------------------------
%Terminal swing. Note: Initial swing is the same as terminal stance 
betha_Rankle_TSw_Idx = CycR_TSw_Step;
betha_Rankle_TSw = betha_Rankle(CycR_TSw_Step);

%Maximum abduction
[betha_Rankle_MaxAbdSw, betha_Rankle_MaxAbdSw_Idx] = arrayfun(@(i, j) min_index(betha_Rankle, i, j), CycR_TSt_Step, CycR_TSw_Step);


%-------------------Left-------------------------
%Terminal swing. Note: Initial swing is the same as terminal stance 
betha_Lankle_TSw_Idx = CycL_TSw_Step;
betha_Lankle_TSw = betha_Lankle(CycL_TSw_Step);

%Maximum abduction
[betha_Lankle_MaxAbdSw, betha_Lankle_MaxAbdSw_Idx] = arrayfun(@(i, j) min_index(betha_Lankle, i, j), CycL_TSt_Step, CycL_TSw_Step);


%% -------------------------------------------------------Ankle total range of movement -----------------------------------------------------------------
%-------------------------------------Sagittal plane-------------------------------------------
%-------------------Right-------------------------
%Maximum flexion
[alpha_Rankle_MaxFlx, alpha_Rankle_MaxFlx_Idx] = arrayfun(@(i, j) max_index(alpha_Rankle, i, j), CycR_ISt_Step, CycR_TSw_Step);

%Maximum extension
[alpha_Rankle_MaxExt, alpha_Rankle_MaxExt_Idx] = arrayfun(@(i, j) min_index(alpha_Rankle, i, j), CycR_ISt_Step, CycR_TSw_Step);
alpha_Rankle_ROM = alpha_Rankle_MaxFlx - alpha_Rankle_MaxExt;

%-------------------Left-------------------------
%Maximum flexion
[alpha_Lankle_MaxFlx, alpha_Lankle_MaxFlx_Idx] = arrayfun(@(i, j) max_index(alpha_Lankle, i, j), CycL_ISt_Step, CycL_TSw_Step);

%Maximum extension
[alpha_Lankle_MaxExt, alpha_Lankle_MaxExt_Idx] = arrayfun(@(i, j) min_index(alpha_Lankle, i, j), CycL_ISt_Step, CycL_TSw_Step);
alpha_Lankle_ROM = alpha_Lankle_MaxFlx - alpha_Lankle_MaxExt;


%-------------------------------------Frontal plane-------------------------------------------
%-------------------Right-------------------------
%Maximum external rotation
[gamma_Rankle_MaxExtR, gamma_Rankle_MaxExtR_Idx] = arrayfun(@(i, j) min_index(gamma_Rankle, i, j), CycR_ISt_Step, CycR_TSw_Step);

%Maximum internal rotation
[gamma_Rankle_MaxIntR, gamma_Rankle_MaxIntR_Idx] = arrayfun(@(i, j) max_index(gamma_Rankle, i, j), CycR_ISt_Step, CycR_TSw_Step);
gamma_Rankle_ROM = gamma_Rankle_MaxIntR - gamma_Rankle_MaxExtR;

%-------------------Left-------------------------
%Maximum external rotation
[gamma_Lankle_MaxExtR, gamma_Lankle_MaxExtR_Idx] = arrayfun(@(i, j) min_index(gamma_Lankle, i, j), CycL_ISt_Step, CycL_TSw_Step);

%Maximum internal rotation
[gamma_Lankle_MaxIntR, gamma_Lankle_MaxIntR_Idx] = arrayfun(@(i, j) max_index(gamma_Lankle, i, j), CycL_ISt_Step, CycL_TSw_Step);
gamma_Lankle_ROM = gamma_Lankle_MaxIntR - gamma_Lankle_MaxExtR;



%-------------------------------------Transverse plane-------------------------------------------
%-------------------Right-------------------------
%Maximum abduction
[betha_Rankle_MaxAbd, betha_Rankle_MaxAbd_Idx] = arrayfun(@(i, j) min_index(betha_Rankle, i, j), CycR_ISt_Step, CycR_TSw_Step);

%Maximum adduction
[betha_Rankle_MaxAdd, betha_Rankle_MaxAdd_Idx] = arrayfun(@(i, j) max_index(betha_Rankle, i, j), CycR_ISt_Step, CycR_TSw_Step);
betha_Rankle_ROM = betha_Rankle_MaxAdd - betha_Rankle_MaxAbd;

%-------------------Left-------------------------
%Maximum flexion
[betha_Lankle_MaxAbd, betha_Lankle_MaxAbd_Idx] = arrayfun(@(i, j) min_index(betha_Lankle, i, j), CycL_ISt_Step, CycL_TSw_Step);

%Maximum adduction
[betha_Lankle_MaxAdd, betha_Lankle_MaxAdd_Idx] = arrayfun(@(i, j) max_index(betha_Lankle, i, j), CycL_ISt_Step, CycL_TSw_Step);
betha_Lankle_ROM = betha_Lankle_MaxAdd - betha_Lankle_MaxAbd;


%% -------------------------------------------------------Ankle stance range of movement -----------------------------------------------------------------
%-------------------------------------Sagittal plane-------------------------------------------
%-------------------Right-------------------------
%Maximum flexion
[alpha_Rankle_MaxFlxStROM, alpha_Rankle_MaxFlxStROM_Idx] = arrayfun(@(i, j) max_index(alpha_Rankle, i, j), CycR_ISt_Step, CycR_TSt_Step);

%Maximum extension
[alpha_Rankle_MaxExtStROM, alpha_Rankle_MaxExtStROM_Idx] = arrayfun(@(i, j) min_index(alpha_Rankle, i, j), CycR_ISt_Step, CycR_TSt_Step);
alpha_Rankle_ROM_ST = alpha_Rankle_MaxFlxStROM - alpha_Rankle_MaxExtStROM;

%-------------------Left-------------------------
%Maximum flexion
[alpha_Lankle_MaxFlxStROM, alpha_Lankle_MaxFlxStROM_Idx] = arrayfun(@(i, j) max_index(alpha_Lankle, i, j), CycL_ISt_Step, CycL_TSt_Step);

%Maximum extension
[alpha_Lankle_MaxExtStROM, alpha_Lankle_MaxExtStROM_Idx] = arrayfun(@(i, j) min_index(alpha_Lankle, i, j), CycL_ISt_Step, CycL_TSt_Step);
alpha_Lankle_ROM_ST = alpha_Lankle_MaxFlxStROM - alpha_Lankle_MaxExtStROM;


%-------------------------------------Frontal plane-------------------------------------------
%-------------------Right-------------------------
%Maximum external rotation
[gamma_Rankle_MaxExtRStROM, gamma_Rankle_MaxExtRStROM_Idx] = arrayfun(@(i, j) min_index(gamma_Rankle, i, j), CycR_ISt_Step, CycR_TSt_Step);

%Maximum internal rotation
[gamma_Rankle_MaxIntRStROM, gamma_Rankle_MaxIntRStROM_Idx] = arrayfun(@(i, j) max_index(gamma_Rankle, i, j), CycR_ISt_Step, CycR_TSt_Step);
gamma_Rankle_ROM_ST = gamma_Rankle_MaxIntRStROM - gamma_Rankle_MaxExtRStROM;

%-------------------Left-------------------------
%Maximum external rotation
[gamma_Lankle_MaxExtRStROM, gamma_Lankle_MaxExtRStROM_Idx] = arrayfun(@(i, j) min_index(gamma_Lankle, i, j), CycL_ISt_Step, CycL_TSt_Step);

%Maximum internal rotation
[gamma_Lankle_MaxIntRStROM, gamma_Lankle_MaxIntRStROM_Idx] = arrayfun(@(i, j) max_index(gamma_Lankle, i, j), CycL_ISt_Step, CycL_TSt_Step);
gamma_Lankle_ROM_ST = gamma_Lankle_MaxIntRStROM - gamma_Lankle_MaxExtRStROM;



%-------------------------------------Transverse plane-------------------------------------------
%-------------------Right-------------------------
%Maximum abduction
[betha_Rankle_MaxAbdStROM, betha_Rankle_MaxAbdStROM_Idx] = arrayfun(@(i, j) min_index(betha_Rankle, i, j), CycR_ISt_Step, CycR_TSt_Step);

%Maximum adduction
[betha_Rankle_MaxAddStROM, betha_Rankle_MaxAddStROM_Idx] = arrayfun(@(i, j) max_index(betha_Rankle, i, j), CycR_ISt_Step, CycR_TSt_Step);
betha_Rankle_ROM_ST = betha_Rankle_MaxAddStROM - betha_Rankle_MaxAbdStROM;

%-------------------Left-------------------------
%Maximum flexion
[betha_Lankle_MaxAbdStROM, betha_Lankle_MaxAbdStROM_Idx] = arrayfun(@(i, j) min_index(betha_Lankle, i, j), CycL_ISt_Step, CycL_TSt_Step);

%Maximum adduction
[betha_Lankle_MaxAddStROM, betha_Lankle_MaxAddStROM_Idx] = arrayfun(@(i, j) max_index(betha_Lankle, i, j), CycL_ISt_Step, CycL_TSt_Step);
betha_Lankle_ROM_ST = betha_Lankle_MaxAddStROM - betha_Lankle_MaxAbdStROM;


