%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
%% FIGURE 102: Individual right/left cycles with transition markers
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% This figure overlays each cycle after setting initial stance to time zero.
% Solid lines are the angle trajectories.
% Dashed vertical lines show transition from stance to swing.
%
% Important note:
% Right side is always black and left side is always blue.
% Solid lines are cycles. Dashed vertical lines are stance-to-swing transitions.
%
% If right and left transition times are almost identical, one line can hide
% the other. The helper below applies a very small display-only separation
% so both right and left transition lines remain visible. The original
% transition values in Trtime_CycR and Trtime_CycL are not changed.

figure(102); clf;

lineWidth  = 1;
fontSize   = 12;

rightColor = rightPlotColor;      % Right side = black
leftColor  = leftPlotColor;       % Left side  = soft blue

maxCycleTime = max([cellfun(@max, Time_CycR); cellfun(@max, Time_CycL)]);
xRangeCycle  = [0, maxCycleTime + 0.02];

% Row 1: alpha angles
subplot(3,3,1);
[jointTitle, yLabelStr] = getAngleLabels('Hip','alpha');
plotRawCyclePanel(Time_CycR, alpha_Rhip_Cyc, Trtime_CycR, ...
                  Time_CycL, alpha_Lhip_Cyc, Trtime_CycL, ...
                  rightColor, leftColor, lineWidth, fontSize, ...
                  jointTitle, yLabelStr, '', xRangeCycle);

subplot(3,3,2);
[jointTitle, yLabelStr] = getAngleLabels('Knee','alpha');
plotRawCyclePanel(Time_CycR, alpha_Rknee_Cyc, Trtime_CycR, ...
                  Time_CycL, alpha_Lknee_Cyc, Trtime_CycL, ...
                  rightColor, leftColor, lineWidth, fontSize, ...
                  jointTitle, yLabelStr, '', xRangeCycle);

subplot(3,3,3);
[jointTitle, yLabelStr] = getAngleLabels('Ankle','alpha');
