function [R_Rhip, R_Rknee, R_Rankle, ...
          R_Lhip, R_Lknee, R_Lankle, ...
          Joint_Angles_Rhip, Joint_Angles_Rknee, Joint_Angles_Rankle, ...
          Joint_Angles_Lhip, Joint_Angles_Lknee, Joint_Angles_Lankle] = ...
          computeJointAnglesFromAxes( ...
              i_pelvis, j_pelvis, k_pelvis, ...
              i_Rfemur, j_Rfemur, k_Rfemur, ...
              i_Rleg,   j_Rleg,   k_Rleg, ...
              i_Rfoot,  j_Rfoot,  k_Rfoot, ...
              i_Lfemur, j_Lfemur, k_Lfemur, ...
              i_Lleg,   j_Lleg,   k_Lleg, ...
              i_Lfoot,  j_Lfoot,  k_Lfoot, ...
              EulerSeq)
%COMPUTEJOINTANGLESFROMAXES Compute relative joint rotations and Euler angles.
%
% Each segment frame is built from its local i, j, and k unit vectors.
% The relative rotation is then converted to Euler angles with rotm2eul().

    if ~strcmp(EulerSeq, 'ZYX') && ~strcmp(EulerSeq, 'XYZ')
        error('EulerSeq must be either ''ZYX'' or ''XYZ''.');
    end

    n = size(i_pelvis, 1);

    R_Rhip   = cell(n, 1);
    R_Rknee  = cell(n, 1);
    R_Rankle = cell(n, 1);
    R_Lhip   = cell(n, 1);
    R_Lknee  = cell(n, 1);
    R_Lankle = cell(n, 1);

    Joint_Angles_Rhip   = zeros(n, 3);
    Joint_Angles_Rknee  = zeros(n, 3);
    Joint_Angles_Rankle = zeros(n, 3);
    Joint_Angles_Lhip   = zeros(n, 3);
    Joint_Angles_Lknee  = zeros(n, 3);
    Joint_Angles_Lankle = zeros(n, 3);

    for t = 1:n
        % Segment frames. Columns are local i, j, and k axes.
        Frame_pelvis = [i_pelvis(t, :); j_pelvis(t, :); k_pelvis(t, :)]';

        Frame_Rfemur = [i_Rfemur(t, :); j_Rfemur(t, :); k_Rfemur(t, :)]';
        Frame_Rleg   = [i_Rleg(t,   :); j_Rleg(t,   :); k_Rleg(t,   :)]';
        Frame_Rfoot  = [i_Rfoot(t,  :); j_Rfoot(t,  :); k_Rfoot(t,  :)]';

        Frame_Lfemur = [i_Lfemur(t, :); j_Lfemur(t, :); k_Lfemur(t, :)]';
        Frame_Lleg   = [i_Lleg(t,   :); j_Lleg(t,   :); k_Lleg(t,   :)]';
        Frame_Lfoot  = [i_Lfoot(t,  :); j_Lfoot(t,  :); k_Lfoot(t,  :)]';

        % Relative rotations. A \ B is used instead of inv(A)*B.
        R_Rhip{t}   = Frame_Rfemur \ Frame_pelvis;
        R_Rknee{t}  = Frame_Rleg   \ Frame_Rfemur;
        R_Rankle{t} = Frame_Rfoot  \ Frame_Rleg;

        R_Lhip{t}   = Frame_Lfemur \ Frame_pelvis;
        R_Lknee{t}  = Frame_Lleg   \ Frame_Lfemur;
        R_Lankle{t} = Frame_Lfoot  \ Frame_Lleg;

        % Euler angles are stored in radians. Conversion to degrees happens
        % in the main script, where signs are set for each joint/side.
        Joint_Angles_Rhip(t,   :) = rotm2eul(R_Rhip{t},   EulerSeq);
        Joint_Angles_Rknee(t,  :) = rotm2eul(R_Rknee{t},  EulerSeq);
        Joint_Angles_Rankle(t, :) = rotm2eul(R_Rankle{t}, EulerSeq);

        Joint_Angles_Lhip(t,   :) = rotm2eul(R_Lhip{t},   EulerSeq);
        Joint_Angles_Lknee(t,  :) = rotm2eul(R_Lknee{t},  EulerSeq);
        Joint_Angles_Lankle(t, :) = rotm2eul(R_Lankle{t}, EulerSeq);
    end
end

function [titleStr, yLabelStr] = getAngleLabels(jointName, angleType)
% GETANGLELABELS
% Returns a title string and y-label string for the given joint/angle.
%
% You can *separately* edit the labels for:
%  - 'Ankle'  (alpha/beta/gamma)
%  - 'Knee'   (alpha/beta/gamma)
%  - 'Hip'    (alpha/beta/gamma)
%
% So you only need to modify them here if you want different text.

%--------------- Define labels for each joint & angle type --------------
%===============================
% ANKLE
%===============================
% alpha = Plantarflexion / Dorsiflexion
ankleAlphaLabel = 'PF(-)-DF(+)°';

% beta = Abduction / Adduction
ankleBetaLabel  = 'ABD(-)-ADD(+)°';

% gamma = Inversion / Eversion
ankleGammaLabel = 'ER/Inv(-)-IR/Ev(+)°';


%===============================
% KNEE
%===============================
% alpha = Extension / Flexion
kneeAlphaLabel = 'EXT(-)-FLEX(+)°';

% beta = Abduction/Adduction + Valgus/Varus
kneeBetaLabel  = 'ABD/Val(-)-ADD/Var(+)°';

% gamma = External/Internal Rotation
kneeGammaLabel = 'ER(-)-IR(+)°';


%===============================
% HIP
%===============================
% alpha = Extension / Flexion
hipAlphaLabel = 'EXT(-)-FLEX(+)°';

% beta = Abduction / Adduction
hipBetaLabel  = 'ABD(-)-ADD(+)°';

% gamma = External / Internal Rotation
hipGammaLabel = 'ER(-)-IR(+)°';


    %------------------------------------------------------------------------

    % 1) Title (e.g., "Hip \alpha", "Knee \beta", "Ankle \gamma")
    switch lower(angleType)
        case 'alpha'
            titleStr = sprintf('%s \\alpha', jointName);
        case 'beta'
            titleStr = sprintf('%s \\beta', jointName);
        case 'gamma'
            titleStr = sprintf('%s \\gamma', jointName);
        otherwise
            titleStr = sprintf('%s (%s)', jointName, angleType);
    end

    % 2) Y-Label depends on joint + angle type
    switch lower(jointName)
        case 'ankle'
            switch lower(angleType)
                case 'alpha'
                    yLabelStr = ankleAlphaLabel;
                case 'beta'
                    yLabelStr = ankleBetaLabel;
                case 'gamma'
                    yLabelStr = ankleGammaLabel;
                otherwise
                    yLabelStr = '(no label)';
            end

        case 'knee'
            switch lower(angleType)
                case 'alpha'
                    yLabelStr = kneeAlphaLabel;
                case 'beta'
                    yLabelStr = kneeBetaLabel;
                case 'gamma'
                    yLabelStr = kneeGammaLabel;
                otherwise
                    yLabelStr = '(no label)';
            end

        case 'hip'
            switch lower(angleType)
                case 'alpha'
                    yLabelStr = hipAlphaLabel;
                case 'beta'
                    yLabelStr = hipBetaLabel;
                case 'gamma'
                    yLabelStr = hipGammaLabel;
                otherwise
                    yLabelStr = '(no label)';
            end

        otherwise
            yLabelStr = '(unknown joint)';
    end
end



function plotRawCyclePanel(Time_CycR, Right_Cyc, Trtime_CycR, ...
                           Time_CycL, Left_Cyc,  Trtime_CycL, ...
                           rightColor, leftColor, lineWidth, fontSize, ...
                           jointTitle, yLabelStr, xLabelStr, xRange)
%PLOTRAWCYCLEPANEL Plot right/left individual cycles and transition lines.
%
% Used only for Figure 102.
%   - Right cycles/transition = black
%   - Left cycles/transition  = soft blue
%   - Solid lines             = angle cycles
%   - Dashed vertical lines   = stance-to-swing transition times
%
% If right and left transition times overlap, one dashed line can hide the
% other. To make both sides visible, this function applies a very small
% display-only separation to overlapping transition lines. The original
% transition values in Trtime_CycR and Trtime_CycL are not modified.

    hold on;
    box on;

    % Display-only settings for overlapping transition lines.
    % Keep this value small relative to the cycle duration.
    transitionOverlapTolerance_s = 0.002;  % If R/L transitions are closer than this, separate them visually
    transitionVisualSeparation_s = 0.004;  % Total visual separation between overlapping R/L transition lines
    transitionLineWidth          = 1.2;

    % Convert transition times to column vectors for consistent indexing.
    trR = Trtime_CycR(:);
    trL = Trtime_CycL(:);

    % Copy original transition times for plotting.
    % These can be shifted slightly only for visualization if R/L overlap.
    trR_plot = trR;
    trL_plot = trL;

    % Separate only near-overlapping right/left transitions.
    % This makes both colors visible without changing the actual data stored
    % in Trtime_CycR and Trtime_CycL.
    if ~isempty(trR) && ~isempty(trL)
        for rr = 1:numel(trR)
            [closestDistance, closestLeftIdx] = min(abs(trL - trR(rr)));
            if closestDistance < transitionOverlapTolerance_s
                trR_plot(rr) = trR(rr) - transitionVisualSeparation_s/2;
                trL_plot(closestLeftIdx) = trL(closestLeftIdx) + transitionVisualSeparation_s/2;
            end
        end
    end

    % Dummy handles for the legend. They do not appear in the plot, but they
    % keep legend colors/styles correct even when many cycles are plotted.
    hRightCycle = plot(nan, nan, '-',  'Color', rightColor, 'LineWidth', lineWidth);
    hRightTrans = plot(nan, nan, '--', 'Color', rightColor, 'LineWidth', transitionLineWidth);
    hLeftCycle  = plot(nan, nan, '-',  'Color', leftColor,  'LineWidth', lineWidth);
    hLeftTrans  = plot(nan, nan, '--', 'Color', leftColor,  'LineWidth', transitionLineWidth);

    % Plot cycle trajectories first.
    for ii = 1:length(Time_CycR)
        plot(Time_CycR{ii,1}, Right_Cyc{ii,1}, ...
            'Color', rightColor, ...
            'LineWidth', lineWidth, ...
            'LineStyle', '-', ...
            'HandleVisibility', 'off');
    end

    for ii = 1:length(Time_CycL)
        plot(Time_CycL{ii,1}, Left_Cyc{ii,1}, ...
            'Color', leftColor, ...
            'LineWidth', lineWidth, ...
            'LineStyle', '-', ...
            'HandleVisibility', 'off');
    end

    % Plot transition lines after the cycles so they remain visible.
    % Plot right first, then left, so blue left transitions are not hidden by
    % black right transitions when they occur at nearly the same time.
    for ii = 1:length(trR_plot)
        xline(trR_plot(ii), '--', ...
            'Color', rightColor, ...
            'LineWidth', transitionLineWidth, ...
            'HandleVisibility', 'off');
    end

    for ii = 1:length(trL_plot)
        xline(trL_plot(ii), '--', ...
            'Color', leftColor, ...
            'LineWidth', transitionLineWidth, ...
            'HandleVisibility', 'off');
    end

    title(jointTitle, 'FontSize', fontSize);
    ylabel(yLabelStr, 'FontSize', fontSize);

    if ~isempty(xLabelStr)
        xlabel(xLabelStr, 'FontSize', fontSize);
    end

    xlim(xRange);

    legend([hRightCycle, hRightTrans, hLeftCycle, hLeftTrans], ...
           {'Right cycles', 'Right transition', 'Left cycles', 'Left transition'}, ...
           'Location', 'best', 'FontSize', 8);
end


function plotNormalizedCyclePanel(Time_Nor, Right_Cyc_Nor, Right_Cyc_Nor_matrix, Trtime_CycR_Nor, ...
                                  Left_Cyc_Nor,  Left_Cyc_Nor_matrix,  Trtime_CycL_Nor, ...
                                  rightColor, leftColor, rightLightColor, leftLightColor, ...
                                  lineWidth_individuals, lineWidth_mean, fontSize, ...
                                  jointTitle, yLabelStr, xLabelStr)
%PLOTNORMALIZEDCYCLEPANEL Plot normalized right/left cycles and means.
%
% Used for Figure 103.
% Right side is always black/gray. Left side is always soft blue.

    hold on;
    box on;

    % Dummy handles keep the legend correct.
    hRightCycles = plot(nan, nan, '-',  'Color', rightLightColor, 'LineWidth', lineWidth_individuals);
    hRightMean   = plot(nan, nan, '-',  'Color', rightColor,      'LineWidth', lineWidth_mean);
    hRightTrans  = plot(nan, nan, '--', 'Color', rightColor,      'LineWidth', 1.0);

    hLeftCycles  = plot(nan, nan, '-',  'Color', leftLightColor,  'LineWidth', lineWidth_individuals);
    hLeftMean    = plot(nan, nan, '-',  'Color', leftColor,       'LineWidth', lineWidth_mean);
    hLeftTrans   = plot(nan, nan, '--', 'Color', leftColor,       'LineWidth', 1.0);

    % Right individual cycles and mean.
    for ii = 1:length(Right_Cyc_Nor)
        plot(Time_Nor, Right_Cyc_Nor{ii,1}, ...
            'LineWidth', lineWidth_individuals, ...
            'Color', rightLightColor, ...
            'HandleVisibility', 'off');
    end
    plot(Time_Nor, mean(Right_Cyc_Nor_matrix, 2), ...
        'LineWidth', lineWidth_mean, ...
        'Color', rightColor, ...
        'HandleVisibility', 'off');
    xline(mean(Trtime_CycR_Nor), '--', ...
        'Color', rightColor, ...
        'LineWidth', 1.0, ...
        'HandleVisibility', 'off');

    % Left individual cycles and mean.
    for ii = 1:length(Left_Cyc_Nor)
        plot(Time_Nor, Left_Cyc_Nor{ii,1}, ...
            'LineWidth', lineWidth_individuals, ...
            'Color', leftLightColor, ...
            'HandleVisibility', 'off');
    end
    plot(Time_Nor, mean(Left_Cyc_Nor_matrix, 2), ...
        'LineWidth', lineWidth_mean, ...
        'Color', leftColor, ...
        'HandleVisibility', 'off');
    xline(mean(Trtime_CycL_Nor), '--', ...
        'Color', leftColor, ...
        'LineWidth', 1.0, ...
        'HandleVisibility', 'off');

    title(jointTitle, 'FontSize', fontSize);
    ylabel(yLabelStr, 'FontSize', fontSize);

    if ~isempty(xLabelStr)
        xlabel(xLabelStr, 'FontSize', fontSize);
    end

    xlim([0, 100]);

    legend([hRightCycles, hRightMean, hRightTrans, hLeftCycles, hLeftMean, hLeftTrans], ...
        {'Right cycles', 'Right mean', 'Right transition', ...
         'Left cycles',  'Left mean',  'Left transition'}, ...
        'Location', 'best', 'FontSize', 8);
end

function addRightLeftLegendToAllPanels(figHandle, rightColor, leftColor, rightLabel, leftLabel)
%ADDRIGHTLEFTLEGENDTOALLPANELS Add simple Right/Left legends to a figure.
%
% The legend uses dummy lines so MATLAB does not accidentally select event
% lines or one of the many cycle curves.

    axesList = findall(figHandle, 'Type', 'axes');

    for aa = 1:numel(axesList)
        ax = axesList(aa);
        hold(ax, 'on');

        hRight = plot(ax, nan, nan, '-', 'Color', rightColor, 'LineWidth', 1.2);
        hLeft  = plot(ax, nan, nan, '-', 'Color', leftColor,  'LineWidth', 1.2);

        legend(ax, [hRight, hLeft], {rightLabel, leftLabel}, ...
            'Location', 'best', 'FontSize', 8);
    end
end

function addRightLeftMeanLegendToAllPanels(figHandle, rightMeanColor, leftMeanColor)
%ADDRIGHTLEFTMEANLEGENDTOALLPANELS Add a consistent right/left legend.
%
% Used for Figure 103. The legend is based on dummy lines, so it does not
% accidentally use the wrong plotted object when many cycle lines exist.

    axesList = findall(figHandle, 'Type', 'axes');

    for aa = 1:numel(axesList)
        ax = axesList(aa);
        hold(ax, 'on');

        hRight = plot(ax, nan, nan, '-', 'Color', rightMeanColor, ...
            'LineWidth', 1.5);
        hLeft = plot(ax, nan, nan, '-', 'Color', leftMeanColor, ...
            'LineWidth', 1.5);

        legend(ax, [hRight, hLeft], {'Right mean', 'Left mean'}, ...
            'Location', 'best', 'FontSize', 8);
    end
end

function displayAndHighlightCurve(src, ~, cycleNum, side)
    % Callback: prints cycle number in console & highlights the clicked line
    fprintf('Cycle_%s_%d\n', side, cycleNum);
    allLines = findall(gca, 'Type', 'Line');
    set(allLines, 'LineWidth', 0.6); 
    set(src, 'LineWidth', 2);
end

function [min_val, min_idx] = min_index(vector, start_idx, end_idx)
    [min_val, local_idx] = min(vector(start_idx:end_idx));
    min_idx = start_idx + local_idx - 1;
end

function [max_val, max_idx] = max_index(vector, start_idx, end_idx)
    [max_val, local_idx] = max(vector(start_idx:end_idx));
    max_idx = start_idx + local_idx - 1;
end
